const Q_ACCOUNTS_2025_MODEL_II=[{"id": "objective>Accounts>2025 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A financial plan of action expressed in monetary terms is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">imprest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidated fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A financial plan of action expressed in monetary terms is known as a budget. A budget is a financial plan for a defined period, often one year, that is known in advance. Budgets may also be set in money terms, but can also be expressed in terms of units of product, hours of labor, etc.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2025 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Resources owned and controlled by a business are classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liabilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drawings</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Resources owned and controlled by a business are classified as 'assets'. Assets are resources or things of value that are owned by a company. They can be tangible or intangible. Tangible assets are physical items, like buildings, trucks, or equipment. Intangible assets, on the other hand, are non-physical resources and rights that have value, such as trademarks and patents.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2025 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suspense account is used in the correction of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all errors in the trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">errors that affect the agreement of a trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">errors that do not affect the agreement of a trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">errors that affect the accuracy of the net profit   </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A suspense account is a temporary account used in accounting to record discrepancies found in a trial balance. It is used when the total debits do not equal the total credits. The difference is recorded in the suspense account, and once the error is found, the suspense account is debited or credited to balance the accounts. Therefore, a suspense account is used in the correction of errors that affect the agreement of a trial balance.</div>", "topic": "SUSPENSE ACCOUNT : ERRORS THAT WILL AFFECT THE AGREEMENT OF THE TRIAL BALANCE"}, {"id": "objective>Accounts>2025 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The objective of a departmental accounts is to ascertain the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of staff in the department </div>", "<div style=\"font-family:Cambria;font-size:17px;\">departmental performance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock held by the departmental </div>", "<div style=\"font-family:Cambria;font-size:17px;\">departmental labour turnover </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objective of departmental accounts is to ascertain the departmental performance. Departmental accounting is a system of accounting where separate accounts are maintained for each department. It allows the business to identify the profitability and performance of each department, which can be useful for decision-making purposes.</div>", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital expenditure is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost of running a business </div>", "<div style=\"font-family:Cambria;font-size:17px;\">money spend on buying goods for resale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">money spend on acquiring fixed assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extra capital paid in by the proprietor </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital expenditure refers to the money spent on acquiring or maintaining fixed assets, such as land, buildings, and equipment. It is considered a capital expenditure when the asset is newly purchased or when money is used towards extending the useful life of an existing asset, such as repairing the roof on a company building. Therefore, the correct option is 'money spend on acquiring fixed assets'.</div>", "topic": "FINANCIAL SYSTEM : METHODS OF RAISING FUNDS"}, {"id": "objective>Accounts>2025 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sales day book is used to record</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash sales of stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit sales of stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and credit sales of stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash sales of fixed assets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sales day book, also known as a sales journal, is used to record credit sales of stock. It is not used to record cash sales of stock because these are typically recorded in the cash book. It is also not used to record both cash and credit sales of stock because these are recorded in separate books. Finally, it is not used to record cash sales of fixed assets because these are typically recorded in the general journal.</div>", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2025 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Provision for depreciation on delivery van is charged to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appropriation account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Provision for depreciation on delivery van is charged to the profit and loss account. Depreciation is the decrease in the value of an asset over time due to wear and tear, obsolescence etc. It is considered an expense and is charged to the profit and loss account to calculate the net profit or loss of a business.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION"}, {"id": "objective>Accounts>2025 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a source document?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Journal proper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sales invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Credit note</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A source document is the original record of a transaction. It provides the evidence that a financial transaction occurred and includes details about the transaction. Examples of source documents include sales invoices, debit notes, and credit notes. A journal proper, on the other hand, is not a source document. It is a book of original entry where miscellaneous credit transactions that do not fit into other specific books of original entry are recorded.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>2025 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A book that contains the account for the financial transactions of an organization is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">journal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ledger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">folio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">register </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A ledger is a book that contains the account for the financial transactions of an organization. It is where all the transactions are posted by debiting and crediting the accounts. A journal, on the other hand, is a book of original entry where transactions are recorded for the first time. A folio is a page number in a ledger or a journal. A register is a record of a specific type of transaction, like a sales register or a purchase register.</div>", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER"}, {"id": "objective>Accounts>2025 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capital of a sole trader changes as a result of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paying wages by cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equipment purchased by cheque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drawings by cheque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods purchase by cheque</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital of a sole trader changes as a result of drawings by cheque. Drawings refer to the money withdrawn from the business by the owner for personal use. This reduces the capital invested in the business, hence changing the capital of the sole trader.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2025 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used before the appropriation bill is approved?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supplementary general warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provisional general warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> reserved expenditure warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virement warrant</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A provisional general warrant is used before the appropriation bill is approved. It authorizes the government to withdraw funds from the consolidated fund for the running of government during the period the appropriation bill is being considered.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2025 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the going concern concept is no longer applicable, the fixed assets are recorded at their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">net book value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">realizable value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross value </div>", "<div style=\"font-family:Cambria;font-size:17px;\">revalued amount</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The going concern concept in accounting assumes that a business will continue to operate indefinitely. If this concept is no longer applicable, it means the business is facing liquidation or closure. In such a case, the fixed assets are recorded at their realizable value, which is the amount that can be recovered from their sale, not their original cost or book value. Hence, the correct answer is 'realizable value'.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION"}, {"id": "objective>Accounts>2025 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>not</strong> a credit item in the Sales Ledger Control Account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cash received </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Discount allowed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dishonoured cheque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Returns inward</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dishonoured cheque is not found at the credit side of sales ledger control account. <br/>  <br/> Dr &nbsp &nbsp &nbsp Format of Sales Ledger Control A/c &nbsp &nbsp &nbsp Cr <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">bal. b/f <br/> credit sales <br/> dishonoured cheque <br/> cash/bank refund <br/> Int. charges in overdue accounts <br/> bal. c/d <br/>  <br/>  <br/>  <br/> </td><td style=\"border:1px solid black;text-align:center;\">xx <br/> xx <br/> xx <br/> xx <br/> xx <br/> xx <br/>  <br/>  <br/>  <br/>  </td><td style=\"border:1px solid black;text-align:center;\">bal. b/f <br/> cash/bank from customers <br/> Discount allowed <br/> Sales returns  <br/> Bad debts <br/> Set off <br/> Bill of exchange <br/> Bill receivable <br/> bal. c/d</td><td style=\"border:1px solid black;text-align:center;\">xx <br/> xx <br/> xx <br/> xx <br/> xx <br/> xx <br/> xx <br/> xx <br/> xx</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">xx</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">xx</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">bal. b/d</td><td style=\"border:1px solid black;text-align:center;\">xx</td><td style=\"border:1px solid black;text-align:center;\">bal. b/d</td><td style=\"border:1px solid black;text-align:center;\">xx</td></tr></table></div></div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The class of share to which payment of dividend depends on profit is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forfeited shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonus shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">preference shares </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinary shares are the shares to which payment of dividend depends on the profit of the company. Dividends on ordinary shares are not fixed and are decided by the board of directors depending on the company's profitability. Forfeited shares are those that have been taken back by the company due to non-payment of calls. Bonus shares are additional shares given to the current shareholders without any additional cost, based upon the number of shares that a shareholder owns. Preference shares are those that have a fixed dividend, which is paid before any dividends are paid to ordinary shareholders.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2025 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In bank reconciliation, when a cash book shows a credit balance, uncredited cheque are: <br/> I. deducted from the cash book balance  <br/> II. added to the bank statement balance  <br/> III. added to the cash book balance </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In bank reconciliation, when the cash book shows a credit balance, it means the bank owes the business. Therefore, uncredited cheques, which are cheques that have been issued by the business but not yet presented to the bank for payment, are deducted from the cash book balance because they represent future payments that the bank will make on behalf of the business. They are not added to the bank statement balance because the bank is not yet aware of them. Therefore, the correct answer is 'I and II only'.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2025 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a <em>self balancing account</em> is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">suspense account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creditors account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors account</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A self-balancing account is an account in a double entry bookkeeping system, the total of which always equals the combined total of the corresponding subsidiary accounts. It is used to check the arithmetical accuracy of the books of accounts. Examples of self-balancing accounts include control accounts like Purchases Ledger Control Account, Sales Ledger Control Account etc. Therefore, the correct answer is 'control account'.</div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2025 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a primary source of entry into the debtors ledger?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Suppliers invoices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Returns outward notes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sales invoices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Payment vouchers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary source of entry into the debtors ledger is the sales invoices. This is because when a company sells goods or services on credit, the customer becomes a debtor to the company. The sales invoice serves as a record of the transaction and is therefore the primary source of entry into the debtors ledger.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is determined in the Trading Account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Factory overheads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost of goods sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Net profit</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Trading Account is a part of the final accounts prepared by a business to determine the gross profit or gross loss of a business. It includes details of direct expenses and revenues. The cost of goods sold is determined in the Trading Account. It is calculated as the sum of the opening stock, purchases and direct expenses minus the closing stock. The cost of goods sold is an important figure as it is subtracted from sales to find the gross profit or loss. The correct option is 'Cost of goods sold'.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2025 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describe trial balance? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It shows all the entries in the books </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It reveals the financial position of a business </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a list of accounting balances on the books </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a special account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A trial balance is a list of all the General ledger accounts (both revenue and capital) contained in the ledger of a business. This list will contain the name of the nominal ledger account and the value of that nominal ledger account. The value of the nominal ledger will hold either a debit balance value or a credit balance value.</div>", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2025 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The balance on the Sales Ledger Control Account at the end of the accounting year represents total </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trade debtors at the end of the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash sales for the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit sales for the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">amount transferred from the Sales Day Book</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance on the Sales Ledger Control Account at the end of the accounting year represents the total trade debtors at the end of the year. This account is used to keep track of the money owed to a business by its customers (debtors).</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a real account? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Building account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Motor Vehicle account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Patent account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Furniture account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year-end and are carried forward. An example of a real account is an asset account, like 'Building account' or 'Motor Vehicle account'. On the other hand, 'Patent account' is an example of a nominal account, which relates to income, expenses, losses or gains.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2025 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a <strong><em>spreadsheet</em></strong> application?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Excel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Word</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Windows</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excel is a spreadsheet application. A spreadsheet is a file made of rows and columns that help sort, organize, and arrange data efficiently. It also provides the flexibility to use a variety of arithmetic operations on the data.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2025 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Into how many major types can general purpose computers be classified?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">six</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">General purpose computers can be classified into three major types: personal computers (PCs), servers, and supercomputers. Personal computers include desktops, laptops, and portable devices like smartphones and tablets. Servers are powerful computers that serve up information to other computers on a network. Supercomputers are extremely powerful computers used for complex tasks like weather forecasting and scientific simulations.</div>", "topic": "INTRODUCTION TO COMPUTER"}, {"id": "objective>Accounts>2025 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are sold at less than the nominal value, it means they are issued at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a premium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">par </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are sold at less than the nominal value, it means they are issued at a discount. The nominal value of a share, also known as the par value, is its face value as stated in the company's constitution. When shares are issued at a price less than the nominal value, they are said to be issued at a discount. This is typically done when a company is in urgent need of cash flow, or when it initially has difficulty finding buyers.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2025 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer this question <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent prepaid 1/01/2014</td><td style=\"border:1px solid black;text-align:center;\">600</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent paid 31/12/2014</td><td style=\"border:1px solid black;text-align:center;\">3,200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent prepaid 31/12/2014</td><td style=\"border:1px solid black;text-align:center;\">400</td></tr></table></div> <br/>  <br/> Rent for 2014 chargeable to the profit and loss account is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,800</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rent for 2014 chargeable to the profit and loss account is calculated by adding the rent paid during the year to the rent prepaid at the beginning of the year and then subtracting the rent prepaid at the end of the year. This gives us ₦3,200 + ₦600 - ₦400 = ₦3,400.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the following information to answer this question <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent prepaid 1/01/2014</td><td style=\"border:1px solid black;text-align:center;\">600</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent paid 31/12/2014</td><td style=\"border:1px solid black;text-align:center;\">3,200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent prepaid 31/12/2014</td><td style=\"border:1px solid black;text-align:center;\">400</td></tr></table></div> <br/> The balance sheet as at 31st December, 2014 will show </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current asset of ₦600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current asset of ₦400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liability of ₦400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liability of ₦600</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance sheet as at 31st December, 2014 will show the amount of rent that has been prepaid and is yet to be used. This is the rent prepaid at the end of the year, which is ₦400.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In preparing a profit and loss account, a decrease in provision for doubtful debts accounts is treated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current assets</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In preparing a profit and loss account, a decrease in provision for doubtful debts is treated as income. This is because the provision for doubtful debts is an estimate of the amount of bad debt that will arise from accounts receivable that have been issued but not yet collected. If the provision decreases, it means that the expected bad debt is less than initially estimated, hence the difference is treated as income.</div>", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED"}, {"id": "objective>Accounts>2025 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cash receipts and payments involving discounts are entered in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">three-column cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two-column cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">analytical cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petty cash book</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cash receipts and payments involving discounts are entered in a three-column cash book. A three-column cash book has columns for discount, cash and bank. This allows for the recording of discounts received or given along with the cash or bank transactions.</div>", "topic": "CASH BOOK : THREE COLUMN CASH BOOK"}, {"id": "objective>Accounts>2025 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following to answer questions 26 to 29<div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">                                                                           #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock  of Raw Materials        </td><td style=\"border:1px solid black;text-align:center;\">                     8000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases                                             </td><td style=\"border:1px solid black;text-align:center;\">                  45000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of Raw materials            </td><td style=\"border:1px solid black;text-align:center;\">                   9500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages                                           </td><td style=\"border:1px solid black;text-align:center;\">                  6450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages                                          </td><td style=\"border:1px solid black;text-align:center;\">                 2800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation - Plant and machinery         </td><td style=\"border:1px solid black;text-align:center;\">                3200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rents and rates                             </td><td style=\"border:1px solid black;text-align:center;\">                  350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening work- in- progress                       </td><td style=\"border:1px solid black;text-align:center;\">              3250          </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing work-in- progress                          </td><td style=\"border:1px solid black;text-align:center;\">             3750  </td></tr></table></div> <br/>  <br/> Cost of raw materials consumed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#53,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#45,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#45,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#43,500</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of raw materials consumed is calculated by adding the opening stock of raw materials to the purchases and then subtracting the closing stock of raw materials.  <br/>  <br/> In this case, the calculation would be 8000 (opening stock) + 45000 (purchases) - 9500 (closing stock)  <br/> = #43500. </div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2025 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">           <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">                                                                           #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock  of Raw Materials        </td><td style=\"border:1px solid black;text-align:center;\">                     8000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases                                             </td><td style=\"border:1px solid black;text-align:center;\">                  45000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of Raw materials            </td><td style=\"border:1px solid black;text-align:center;\">                   9500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages                                           </td><td style=\"border:1px solid black;text-align:center;\">                  6450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages                                          </td><td style=\"border:1px solid black;text-align:center;\">                 2800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation - Plant and machinery         </td><td style=\"border:1px solid black;text-align:center;\">                3200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rents and rates                             </td><td style=\"border:1px solid black;text-align:center;\">                  350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening work- in- progress                       </td><td style=\"border:1px solid black;text-align:center;\">              3250          </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing work-in- progress                          </td><td style=\"border:1px solid black;text-align:center;\">             3750  </td></tr></table></div>Prime cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#53,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#52,750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#49,950</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#46,300</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost = cost of raw materials consumed + direct expenses <br/>                        = 43,500 + 6450 <br/>                            =#49,950</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2025 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">           <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">                                                                           #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock  of Raw Materials        </td><td style=\"border:1px solid black;text-align:center;\">                     8000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases                                             </td><td style=\"border:1px solid black;text-align:center;\">                  45000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of Raw materials            </td><td style=\"border:1px solid black;text-align:center;\">                   9500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages                                           </td><td style=\"border:1px solid black;text-align:center;\">                  6450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages                                          </td><td style=\"border:1px solid black;text-align:center;\">                 2800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation - Plant and machinery         </td><td style=\"border:1px solid black;text-align:center;\">                3200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rents and rates                             </td><td style=\"border:1px solid black;text-align:center;\">                  350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening work- in- progress                       </td><td style=\"border:1px solid black;text-align:center;\">              3250          </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing work-in- progress                          </td><td style=\"border:1px solid black;text-align:center;\">             3750  </td></tr></table></div>Factory cost of production is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#56,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#53,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#52,750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#45,500</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factory cost of production is calculated as the prime cost plus factory overheads. Factory overheads include indirect wages, depreciation, and factory rents and rates. Therefore, the factory cost of production is 52950 + (2800 + 3200 + 350) = 56300.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2025 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">           <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">                                                                           #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock  of Raw Materials        </td><td style=\"border:1px solid black;text-align:center;\">                     8000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases                                             </td><td style=\"border:1px solid black;text-align:center;\">                  45000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of Raw materials            </td><td style=\"border:1px solid black;text-align:center;\">                   9500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages                                           </td><td style=\"border:1px solid black;text-align:center;\">                  6450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages                                          </td><td style=\"border:1px solid black;text-align:center;\">                 2800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation - Plant and machinery         </td><td style=\"border:1px solid black;text-align:center;\">                3200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rents and rates                             </td><td style=\"border:1px solid black;text-align:center;\">                  350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening work- in- progress                       </td><td style=\"border:1px solid black;text-align:center;\">              3250          </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing work-in- progress                          </td><td style=\"border:1px solid black;text-align:center;\">             3750  </td></tr></table></div>Production cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#57,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#56,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#55,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#53,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">production cost = factory cost of production + opening W.I.P - Closing W.I.P <br/>                                  =56,300 + 3,250 - 3,750 <br/>                                     =   #55,800</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2025 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a source document?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Credit note </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Invoice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit note </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bank note</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bank note is not a source document. In accounting, source documents are the physical or electronic documents that provide evidence of a financial transaction. These include invoices, receipts, credit notes, and debit notes. A bank note, on the other hand, is a type of negotiable instrument issued by a bank, and it is not a document that records a specific business transaction.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>2025 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer questions 6 to 8Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month: <br/>  <br/> Dec. 1      petty cash in hand                                    517 <br/>          1      petty cash to imprest                               3,483 <br/>          6      Bought notebooks                                    328 <br/>          7      Paid wages                                                914 <br/>          14    Bought postages stamps                          375 <br/>          16    Paid to J. Thomas, a creditor                   536 <br/>           21   Paid wages                                                928 <br/>           23   Bought envelopes                                     437 <br/>           27   Bought postages stamps                          210 <br/>  <br/> Amount to be posted to the personal ledger is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#765</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#585</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#536</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#517</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the imprest system, the amount to be posted to the personal ledger is the amount paid to a creditor. In this case, the amount paid to J. Thomas, a creditor, is #536. Therefore, the correct answer is '#536'.</div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2025 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month: <br/>  <br/> Dec. 1      petty cash in hand                                    517 <br/>          1      petty cash to imprest                               3,483 <br/>          6      Bought notebooks                                    328 <br/>          7      Paid wages                                                914 <br/>          14    Bought postages stamps                          375 <br/>          16    Paid to J. Thomas, a creditor                   536 <br/>           21   Paid wages                                                928 <br/>           23   Bought envelopes                                     437 <br/>           27   Bought postages stamps                          210  <br/>  <br/> Amount spent on stationery is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#765</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#585</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#538</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#437</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount spent on stationery is the sum of the amounts spent on notebooks and envelopes, which is #328 + #437 = #765.</div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2025 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month: <br/>  <br/> Dec. 1      petty cash in hand                                    517 <br/>          1      petty cash to imprest                               3,483 <br/>          6      Bought notebooks                                    328 <br/>          7      Paid wages                                                914 <br/>          14    Bought postages stamps                          375 <br/>          16    Paid to J. Thomas, a creditor                   536 <br/>           21   Paid wages                                                928 <br/>           23   Bought envelopes                                     437 <br/>           27   Bought postages stamps                          210  <br/>  <br/> Amount to be reimbursed at the end of the month is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#4,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3,728</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3,483</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1,842</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount to be reimbursed at the end of the month is the total amount spent during the month, which is #328 (notebooks) + #914 (wages) + #375 (postage stamps) + #536 (J. Thomas, a creditor) + #928 (wages) + #437 (envelopes) + #210 (postage stamps) = #3,728.</div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2025 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not credited to debtors control account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Provision for bad debt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bad debts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Discounts allowed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bills receivable </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Provision for bad debts is not credited to debtors control account. It is not an item of debtors control account. It is always ignored when it is given.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2025 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following transactions is a revenue expenditure? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Purchase of a plant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Purchase of a new engine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Construction of office wall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Purchase of fuel for vehicle </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Revenue expenditure refers to the expenditure which is incurred on day to day conduct of business operations, but which has benefits lasting for a period of less than one year. These are recurring or operational expenses that are necessary for the daily business operations and are written off in the same accounting year in which they are incurred. Purchase of fuel for vehicle is a good example of revenue expenditure as it is a recurring expense and its benefit lasts for a period of less than one year.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2025 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the component of factory overheads is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials consumed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing wages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carriage inwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">depreciation of plant and machinery </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factory overheads are the indirect costs incurred during the manufacturing process. These include depreciation of plant and machinery, utilities, rent, and indirect labor. Therefore, the correct answer is 'depreciation of plant and machinery'. Raw materials consumed and manufacturing wages are direct costs, not overheads. Carriage inwards is a cost related to the transportation of raw materials from a supplier, which is also not an overhead cost.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2025 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of distributing shares to successful applicants is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allocation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">apportionment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allotment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">application </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of distributing shares to successful applicants is known as allotment. Allotment is the process by which a company allocates its securities to the successful applicants. The term 'allocation' refers to the process of assigning resources for specific tasks or purposes, while 'apportionment' refers to the process of dividing and distributing something in proportion or according to a plan. 'Application' refers to the process of making a formal request, in this case, for shares.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}];
